INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optician-moex-00719', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '除了日拋型隱形眼鏡之外，所有的隱形眼鏡在每次使用之後都需要透過清潔與保養，鏡片必須安全地儲存 在溶液中。為何需要消毒隱形眼鏡的理由，下列敘述何者錯誤？', '["眼睛有許多抗感染的內在保護機制", "隱形眼鏡配戴者的感染風險比例是非配戴者的60倍", "有5%的人口的淚膜中，無論何時均存在著潛在的病原體，但是眼睛表面有感染狀況者卻遠高於此比例", "淚膜和眨眼過程在抵抗感染中產生重要的作用。基礎淚液的產量為1~2 μl/min，整體總淚液量為7μl， 這證實淚液在眼睛表面的快速更新，可以隨之清除微生物"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00720', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關軟式隱形眼鏡保養系統的物理方法相關敘述，下列何者錯誤？', '["軟式隱形眼鏡消毒的各種物理方法是以引起致命性的細胞變化，達到消毒效果", "物理清潔的消毒方法是1972年由美國食品和藥物管理局（FDA）批准的第一種軟式隱形眼鏡消毒方法", "物理清潔的消毒方法需要80℃的溫度並保存至少維持10分鐘", "加熱消毒有許多優點，在加熱鏡片之後鏡片表面的蛋白質依然不會變性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00721', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡保養液中防腐劑的敘述，下列何者錯誤？', '["氯己定（chlorhexidine），常添加於軟式隱形眼鏡保養液中，一般使用濃度為0.0005%", "與其他防腐劑相比較，硫柳汞（thiomersal）具有較高抗菌作用，也不容易引發敏感反應", "氯己定若單獨使用於透氣硬式隱形眼鏡（RGPlens）保養液，其殺菌效果不佳", "氯己定通常合併添加EDTA（乙二胺四乙酸）以提高抗菌效果"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00722', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關配戴透氣硬式隱形眼鏡（RGPlens）的適應（adaptation），下列何者錯誤？', '["通常第一天只能戴4小時", "配戴初期偶爾會流淚，對光線敏感，乃是正常現象", "如果有嚴重而持續的光暈（haloes）乃屬不正常現象", "一般而言，至少需要28天才能適應"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00723', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於硬式隱形眼鏡護理，下列敘述何者錯誤？', '["清潔時應小心將鏡片置於指腹上以指尖搓揉", "在無法使用吸盤取下鏡片的緊急情況下，可將頭部放置於裝滿水的水槽中，眼睛打開使鏡片脫離眼睛", "使用高Dk材料之鏡片，清潔時較易發生鏡片翹曲（warpage）現象", "如果鏡片掉在堅硬的表面上，可以將一滴潤濕液放在手指上，輕輕地將鏡片從上面上抬起，以減少刮痕"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00724', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何者不是診斷驗配法（diagnosticfitting）的優點？', '["使用角膜地圖儀輔助鏡片設計", "更少再次訂片", "驗光師有信心的驗配", "配戴者滿意度高"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00725', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於透氣硬式隱形眼鏡持續向上偏位，眨眼也無法掉落的原因及處理方法，下列何者錯誤？', '["如果是鏡片邊緣太厚造成的，可訂製周邊正透鏡片設計", "如果是鏡片太薄或太輕造成的，可增加中心厚度來改善", "如果是鏡片太陡造成的，可使用較平基弧的鏡片", "如果是鏡片過大導致眼皮接觸過多，可減少鏡片直徑"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00726', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於驗配硬式隱形眼鏡時發生鏡片偏位（decentration），下列何者錯誤？', '["若角膜有順散光，易使鏡片偏向旁邊（sideway）", "若是鏡片的光學區仍有涵蓋瞳孔，原則上還可接受", "有可能是鏡片的基弧弧度太平", "可考慮換成較大片的鏡片"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00727', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '在設計高度負屈光度透氣硬式隱形眼鏡鏡片時，所考量的參數，下列何者正確？', '["選擇比角膜弧度更陡峭的基弧半徑", "選擇較大的鏡片直徑", "選擇較薄的中心厚度", "選擇負透鏡邊緣設計"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00728', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於幫病人配戴軟式隱形眼鏡的敘述，下列何者錯誤？', '["先將鏡片放在食指與中指間，用消毒水沖洗潤濕", "請病人的眼睛看向對側，將隱形眼鏡放在球結膜（bulbarconjunctiva）處", "再請病人看回正中央", "若病人覺得不舒服，可能是在鏡片表面有異物，此時可以將鏡片移至球結膜再取出"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
